62	func samePath(a, b string) bool {
63		if a == "" || b == "" {
64			return false
65		}
66		cleanA, err := filepath.Abs(a)
67		if err != nil {
68			cleanA = filepath.Clean(a)
69		}
70		cleanB, err := filepath.Abs(b)
71		if err != nil {
72			cleanB = filepath.Clean(b)
73		}
74		if resolvedA, err := filepath.EvalSymlinks(cleanA); err == nil {
75			cleanA = resolvedA
76		}
77		if resolvedB, err := filepath.EvalSymlinks(cleanB); err == nil {
78			cleanB = resolvedB
79		}
80		return cleanA == cleanB
81	}
