83	// FindNearestDDxWorkspace walks up from startDir to find the nearest ancestor
84	// inside the current git repository that contains a .ddx workspace.
85	//
86	// When startDir is inside a linked git worktree (e.g. an execute-bead
87	// isolated worktree under .ddx/.execute-bead-wt-* or a worktrunk sibling
88	// like repo.feature-branch/), it resolves to the PRIMARY worktree's .ddx/
89	// first, not the linked worktree's own .ddx/. This is critical because:
90	//
91	//   - bead store mutations must land in the canonical project bead queue,
92	//     not in an isolated worktree's private snapshot that will be discarded
93	//   - the primary worktree is the operator's source of truth; linked
94	//     worktrees are ephemeral execution contexts
95	//
96	// If no in-tree .ddx/ exists, it falls back to the canonical project root so
97	// callers can still route project state through ddxroot.Path for convention-
98	// root projects.
99	//
100	// Returns an empty string only when startDir is not inside a git repository
101	// and no ancestor contains .ddx/.
102	func FindNearestDDxWorkspace(startDir string) string {
103		abs, err := filepath.Abs(startDir)
104		if err != nil {
105			return ""
106		}
107	
108		// If we're inside a linked worktree, prefer the primary worktree's .ddx/.
109		if primary := primaryWorktreeRoot(abs); primary != "" && primary != FindProjectRoot(abs) {
110			return primary
111		}
112	
113		gitRoot := FindProjectRoot(abs)
114		current := abs
115		for {
116			candidate := filepath.Join(current, ddxDirSegment)
117			if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
118				return current
119			}
120			if current == gitRoot {
121				break
122			}
123			parent := filepath.Dir(current)
124			if parent == current {
125				break
126			}
127			current = parent
128		}
129	
130		if IsRepository(abs) {
131			return gitRoot
132		}
133		return ""
134	}
