136	// IsRepository checks if the current directory is a git repository.
137	func IsRepository(path string) bool {
138		if path == "" {
139			path = "."
140		}
141	
142		cleanPath := filepath.Clean(path)
143		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
144		defer cancel()
145	
146		cmd := Command(ctx, cleanPath, "rev-parse", "--git-dir")
147		return cmd.Run() == nil
148	}
