150	// primaryWorktreeRoot returns the primary (non-linked) worktree directory
151	// for a given path inside a git repository, or "" if the path is not inside
152	// a linked worktree (or if resolution fails).
153	//
154	// Detection: `git rev-parse --git-common-dir` returns the shared .git
155	// directory. If that differs from `git rev-parse --git-dir`, we're in a
156	// linked worktree. The primary worktree is the parent directory of the
157	// common .git dir (unless the shared dir is a bare repo).
158	func primaryWorktreeRoot(startDir string) string {
159		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
160		defer cancel()
161	
162		gitDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-dir")
163		gitDirOut, err := gitDirCmd.Output()
164		if err != nil {
165			return ""
166		}
167		gitDir := strings.TrimSpace(string(gitDirOut))
168	
169		commonDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-common-dir")
170		commonDirOut, err := commonDirCmd.Output()
171		if err != nil {
172			return ""
173		}
174		commonDir := strings.TrimSpace(string(commonDirOut))
175	
176		if gitDir == commonDir {
177			// Not a linked worktree.
178			return ""
179		}
180	
181		// Common dir is either a bare repo or the primary worktree's .git dir.
182		// If it's a .git directory, the primary worktree is its parent.
183		if filepath.Base(commonDir) == ".git" {
184			return filepath.Dir(commonDir)
185		}
186		// Bare repo: no primary worktree. Caller falls back to walk-up.
187		return ""
188	}
