881			// them a fresh per-attempt home has no live cloud provider and routing
882			// fails with no_viable_provider. Seed the snapshots from the host.
883			{filepath.Join(hostHome, ".local", "state", "fizeau", "claude-quota.json"), filepath.Join(homeDir, ".local", "state", "fizeau", "claude-quota.json")},
884			{filepath.Join(hostHome, ".local", "state", "fizeau", "codex-quota.json"), filepath.Join(homeDir, ".local", "state", "fizeau", "codex-quota.json")},
885			{filepath.Join(hostHome, ".local", "state", "fizeau", "gemini-quota.json"), filepath.Join(homeDir, ".local", "state", "fizeau", "gemini-quota.json")},
886		} {
