944		if err != nil || rel == "." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) || rel == ".." {
945			return "", fmt.Errorf("docker-clone prompt file must be inside the attempt workspace: %s", path)
946		}
947		return filepath.ToSlash(filepath.Join("/work", rel)), nil
948	}
