// isProjectRootDirtyForDrain reports whether the canonical project root has
// uncommitted changes to non-DDx files. DDx-managed paths under .ddx/ are
// excluded because beads.jsonl and config files are legitimately modified
// during normal operation without always being staged. Fail-open on errors so
// a bare repo or git-less environment does not block the worker.
func isProjectRootDirtyForDrain(projectRoot string) (bool, error) {
	if projectRoot == "" {
		return false, nil
	}
	out, err := internalgit.Command(context.Background(), projectRoot, "status", "--porcelain").Output()
	if err != nil {
		return false, nil // fail-open: non-git or inaccessible root
	}
	for _, line := range strings.Split(string(out), "\n") {
		line = strings.TrimRight(line, "\r")
		if strings.TrimSpace(line) == "" || len(line) < 3 {
			continue
		}
		path := strings.TrimSpace(line[3:])
		if idx := strings.Index(path, " -> "); idx >= 0 {
			path = strings.TrimSpace(path[idx+4:])
		}
		if path == "" || strings.HasPrefix(path, ".ddx/") || path == ".ddx" {
			continue
		}
		return true, nil
	}
	return false, nil
}

