// Dirty-root guard: refuse to drain a WIP canonical checkout. A dirty root
// means the operator or another workflow has active uncommitted changes that
// the autonomous worker must not overwrite (FEAT-004 addendum, ddx-2a24727c).
// Fail-open when ProjectRoot is empty or git is unavailable so non-git
// environments and existing tests that omit ProjectRoot are unaffected.
if runtime.ProjectRoot != "" {
	if dirty, _ := w.effectiveRootDirtyChecker()(runtime.ProjectRoot); dirty {
		detail := fmt.Sprintf(
			"canonical project root %s has uncommitted non-DDx changes; resolve WIP before autonomous drain",
			runtime.ProjectRoot,
		)
		result.OperatorAttention = &OperatorAttentionStop{
			Reason:      "dirty_project_root",
			ProjectRoot: runtime.ProjectRoot,
			Message:     detail,
		}
		setExit("OperatorAttention", "operator_attention")
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", detail)
		}
		emit("loop.operator_attention", map[string]any{
			"reason":       "dirty_project_root",
			"project_root": runtime.ProjectRoot,
			"message":      detail,
		})
		return result, nil
	}
}

