package agent

import (
	"context"
	"os"
	"path/filepath"
	"sync/atomic"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestDirtyRootGuard_WIPChurnStopped is the AC #3 regression guard for bead
// ddx-2a24727c. It reproduces the helix-style dirty-WIP churn: a worker
// started against a canonical root with uncommitted non-DDx changes must stop
// immediately with an operator-attention signal rather than claiming any bead
// and entering the drain loop.
func TestDirtyRootGuard_WIPChurnStopped(t *testing.T) {
	root := t.TempDir()
	require.NoError(t, os.MkdirAll(filepath.Join(root, ddxroot.DirName), 0o755))
	require.NoError(t, os.WriteFile(
		filepath.Join(root, ddxroot.DirName, "config.yaml"),
		[]byte("version: \"1.0\"\n"),
		0o644,
	))

	rcfg, err := config.LoadAndResolve(root, config.CLIOverrides{Assignee: "worker"})
	require.NoError(t, err)

	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:       "ddx-dirty-root-bead",
		Title:    "bead that must not be claimed on dirty root",
		Priority: 0,
	}))

	var execCalls int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCalls, 1)
			return ExecuteBeadReport{Status: ExecuteBeadStatusSuccess, BeadID: beadID}, nil
		}),
		rootDirtyChecker: func(string) (bool, error) { return true, nil },
	}

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:        true,
		ProjectRoot: root,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// No bead claimed or executed — the worker stopped before the drain loop.
	assert.Equal(t, int32(0), atomic.LoadInt32(&execCalls),
		"executor must not be invoked when the project root is dirty")
	assert.Equal(t, 0, result.Attempts, "no bead attempts must be recorded on a dirty root")

	// Worker stopped with a clear operator-attention signal.
	require.NotNil(t, result.OperatorAttention,
		"worker must emit operator-attention when the project root is dirty")
	assert.Equal(t, "dirty_project_root", result.OperatorAttention.Reason)
	assert.Contains(t, result.OperatorAttention.Message, "uncommitted")
	assert.Equal(t, root, result.OperatorAttention.ProjectRoot)
	assert.Equal(t, "OperatorAttention", result.StopCondition)
}
